def ejecutar_tool(nombre, input_):
    if nombre == "obtener_clima":
        return f"18°C en {input_['ciudad']}"
    raise ValueError(f"tool desconocida: {nombre}")

def conversar(mensajes, tools):
    while True:
        response = client.messages.create(
            model="claude-sonnet-4-6", max_tokens=800, tools=tools, messages=mensajes
        )
        mensajes.append({"role": "assistant", "content": response.content})

        if response.stop_reason != "tool_use":
            return response

        resultados_tools = []
        for bloque in response.content:
            if bloque.type == "tool_use":
                salida = ejecutar_tool(bloque.name, bloque.input)
                resultados_tools.append({
                    "type": "tool_result", "tool_use_id": bloque.id, "content": salida
                })
        mensajes.append({"role": "user", "content": resultados_tools})
